curr_mod = mod_tree

number_guesses_offset = 0

def stringify_node(tree):
    if tree['type'] == 'number':
        return f"{{type: 'number', n: {tree['n']}}}"
    else:
        return str(tree)

def define_rule_routine(number_guesses):
    global rule_tree_curr
    global rule_probs, rule_argmax, rule_2argmax, rule_3argmax, number_guesses_offset, rule_priority_list

    if rule_tree_curr['type'] == 'rule':
        # achamos a regra, ent setamos tudo
        rule_probs = rule_tree_curr['probabilities']
        #print(rule_probs)
        rule_argmax, rule_2argmax, rule_3argmax = sorted(rule_probs, key=rule_probs.get, reverse=True)[:3]
        rule_priority_list = [rule_argmax, rule_2argmax, rule_3argmax]
        rule_idx = 0
        return -1 # -1 pq nao vamos chutar nenhum numero

    # agr percorremos a tree mais uma vez, com base no último resultado (number_guesses[-1]) (a n ser q seja a primeira guess, aí so retornamos como ta)
    if len(number_guesses) == 0:
        return ["NUMBER", rule_tree_curr['n']]
    
    direction = number_guesses[-1][1]
    guess_n = rule_tree_curr['n']
    rule_tree_curr = rule_tree_curr['branches'][direction]
    return ["NUMBER", guess_n]

interval_state = {
    "active": False,        # se estamos no modo INT
    "n_start": -1,          # um número que satisfaz a regra
    "found_a": False,
    "found_b": False,
    "left_bs_left": -1,
    "left_bs_right": -1,
    "right_bs_left": -1,
    "right_bs_right": -1,
    "interval_a": -1,
    "interval_b": -1,
    "last_processed": -1,
    # busca inicial do n_start (galloping) – só usamos se a árvore não deu um n_start
    "gallop_left": -1,
    "gallop_right": -1,
    "gallop_exp": 0,
    "gallop_phase": "gallop",
    "attempts": -1
}

number_direction_type = {"GREATER": "maior", "LESS": "menor"}

def get_interval_bounds_from_history(number_guesses, n_start):
    left_bound = 1
    right_bound = 100_000
    closest_left_invalid = -1
    closest_right_invalid = 100_001
    for guess, direction, is_valid in number_guesses:
        if not is_valid:
            if guess < n_start:
                closest_left_invalid = max(closest_left_invalid, guess)
            elif guess > n_start:
                closest_right_invalid = min(closest_right_invalid, guess)
    if closest_left_invalid != -1:
        left_bound = closest_left_invalid + 1
    if closest_right_invalid != 100_001:
        right_bound = closest_right_invalid - 1
    return left_bound, right_bound

def interval_player_step(number_guesses, rule_guesses):
    """Executa um passo da lógica INT (intervalo). Retorna uma ação."""
    s = interval_state
    s["attempts"] += 1

    # Se ainda não temos um n_start, tenta obtê‑lo da árvore ou via galloping
    if s["n_start"] == -1:
        # Verifica se a árvore já nos deu um número válido nos guesses anteriores
        if len(number_guesses) and number_guesses[-1][2]:
            s["n_start"] = number_guesses[-1][0]
        else:
            if s["gallop_left"] == -1:
                s["gallop_left"] = 1
                s["gallop_right"] = 100_000
                return [CHUTE_DE_NUMERO, 1]
            last_guess, direction, _ = number_guesses[-1]
            if s["gallop_phase"] == "gallop":
                if direction == number_direction_type["GREATER"]:
                    s["gallop_left"] = last_guess + 1
                    s["gallop_exp"] += 7
                    next_guess = 2 ** s["gallop_exp"]
                    if next_guess >= 100_000:
                        s["gallop_phase"] = "bs"
                        s["gallop_right"] = 100_000
                        return [CHUTE_DE_NUMERO, (s["gallop_left"] + s["gallop_right"]) // 2]
                    return [CHUTE_DE_NUMERO, next_guess]
                else:
                    s["gallop_right"] = last_guess - 1
                    s["gallop_phase"] = "bs"
                    return [CHUTE_DE_NUMERO, (s["gallop_left"] + s["gallop_right"]) // 2]
            else:
                if direction == number_direction_type["LESS"]:
                    s["gallop_right"] = last_guess - 1
                elif direction == number_direction_type["GREATER"]:
                    s["gallop_left"] = last_guess + 1
                return [CHUTE_DE_NUMERO, (s["gallop_left"] + s["gallop_right"]) // 2]

    # Já temos n_start – busca os limites a e b
    if len(number_guesses) > s["last_processed"]:
        last_guess, direction, is_valid = number_guesses[-1]
        if s["left_bs_left"] != -1:
            if not s["found_a"]:
                if is_valid:
                    s["left_bs_right"] = last_guess
                else:
                    if direction == number_direction_type["GREATER"]:
                        s["left_bs_left"] = last_guess + 1
                    else:
                        s["left_bs_right"] = last_guess - 1
            elif not s["found_b"]:
                if is_valid:
                    s["right_bs_left"] = last_guess
                else:
                    if direction == number_direction_type["LESS"]:
                        s["right_bs_right"] = last_guess - 1
                    else:
                        s["right_bs_left"] = last_guess + 1
        s["last_processed"] = len(number_guesses)

    # Inicializar busca de a
    if s["left_bs_left"] == -1:
        base_left, base_right = get_interval_bounds_from_history(number_guesses, s["n_start"])
        s["left_bs_left"] = max(base_left, max(1, s["n_start"] - 100))
        s["left_bs_right"] = s["n_start"]

    if not s["found_a"]:
        if s["left_bs_left"] >= s["left_bs_right"]:
            s["interval_a"] = s["left_bs_left"]
            s["found_a"] = True
            base_left, base_right = get_interval_bounds_from_history(number_guesses, s["n_start"])
            s["right_bs_left"] = s["n_start"]
            s["right_bs_right"] = min(base_right, min(100_000, s["interval_a"] + 100))
        else:
            return [CHUTE_DE_NUMERO, (s["left_bs_left"] + s["left_bs_right"]) // 2]

    if s["found_a"] and not s["found_b"]:
        if s["right_bs_left"] >= s["right_bs_right"]:
            s["interval_b"] = s["right_bs_right"]
            s["found_b"] = True
        else:
            return [CHUTE_DE_NUMERO, (s["right_bs_left"] + s["right_bs_right"] + 1) // 2]

    if s["found_a"] and s["found_b"]:
        return [CHUTE_DE_REGRA, ["int", s["interval_a"], s["interval_b"]]]

    # Fallback – nunca deve chegar aqui
    return [CHUTE_DE_NUMERO, 1]


def player(number_guesses, rule_guesses):
    global pot_tree
    global curr_pot
    global mod_tree, curr_mod
    global number_guesses_offset
    global HAS_DEFINED_RULE
    if not HAS_DEFINED_RULE:
        guess = define_rule_routine(number_guesses)
        if guess == -1:
            # print("ACHOU A REGRA: ", rule_argmax)
            HAS_DEFINED_RULE = True
            number_guesses_offset = len(number_guesses)
        else:
            return guess
    
    rule_idx = len(rule_guesses) # se erramos uma rule, é pq não é essa rule, e sim a próxima, entao damos um passo no vetor de rules
    number_guesses = number_guesses[number_guesses_offset:]

    if rule_idx > 1:
        return ["RULE", ["pot", 1, -1]]

    if rule_priority_list[rule_idx] == "int":
        return interval_player_step(number_guesses, rule_guesses)

    if rule_priority_list[rule_idx] == "pot":
        # resolvemos usando a tree do pot
        if len(number_guesses) == 0:
            # é a primeira guess
            return ['NUMBER', curr_pot['n']]
        else:
            guess = number_guesses[-1]
            curr_pot = curr_pot['branches'][guess[1]]
        
        
        if curr_pot['type'] == 'number':
            return ['NUMBER', curr_pot['n']]
        else:
            return ['RULE', ['pot', curr_pot['p'], -1]]

    if rule_priority_list[rule_idx] == "mod":
        if len(number_guesses) == 0:
            return ['NUMBER', curr_mod['n']]
        else:
            try:
                guess = number_guesses[-1]
                curr_mod = curr_mod['branches'][guess[1]]
            except KeyError: # key error significa que nao é essa rule, pq fomos numa path q nao existe
                return ["RULE", ['int', 1, 100]]

        if curr_mod['type'] == 'number':
            return ['NUMBER', curr_mod['n']]
        else:
            return ['RULE', ['mod', curr_mod['k'], curr_mod['r']]]

    return ["RULE", ["pot", 1, -1]]

